import {
  FilterFieldGroupNode,
  FilterFieldLeafNode,
  FilterFieldListNode,
  FilterFieldNode,
  FilterFieldStatementNode,
} from '../types/tree-nodes.js';
import type { FilterFieldValidatorMap } from '../types/validation.js';
import { convertStringToFilterFieldTree } from '../utils/conversion/string-tree-conversion.js';
import { convertFilterFieldTreeToString } from '../utils/conversion/tree-string-conversion.js';
import { RESERVED_CHARACTERS } from '../utils/escape-suggestion.js';

/**
 * Replacement map for obfuscating filter values based on their type.
 * Each character in the original value will be replaced with the corresponding
 * replacement character while preserving the original length.
 * @internal
 */
const TYPE_REPLACEMENT_MAP = {
  Key: 'k',
  String: 's',
  JSONPath: 'j',
  Variable: 'v',
  Number: 'n',
  BigInt: 'b',
  Duration: 'd',
  IPAddress: 'i',
  Error: 'e',
  UID: 'u',
  SmartscapeId: 'c',
  Timestamp: 't',
  // The following are not obfuscated
  LogicalOperator: null,
  ComparisonOperator: null,
  ExistsOperator: null,
  SearchOperator: null,
  InclusionOperator: null,
  Boolean: null,
} as const;

// We include the dot in the reserved characters for IPAddress and JSONPath types to preserve them during obfuscation.
const EXTENDED_RESERVED_CHARACTERS = `.${RESERVED_CHARACTERS}`;

function getReplacementChar(node: FilterFieldLeafNode): string | null {
  if (node.type in TYPE_REPLACEMENT_MAP) {
    return TYPE_REPLACEMENT_MAP[node.type];
  }
  return 'U'; // unknown type;
}

function obfuscateText(
  textValue: string | undefined,
  replacementChar: string,
): string {
  if (textValue === undefined) {
    return '';
  }
  return textValue
    .split('')
    .map((char) => {
      if (EXTENDED_RESERVED_CHARACTERS.includes(char)) {
        return char;
      }
      return replacementChar;
    })
    .join('');
}

function obfuscateFilterFieldLeafNode<
  T extends FilterFieldLeafNode | FilterFieldListNode | undefined,
>(node: T): T {
  if (node === undefined) {
    return node;
  }

  if (node.type === 'List') {
    return {
      ...node,
      value: node.value.map((value) => obfuscateFilterFieldLeafNode(value)),
    };
  }

  const replacementChar = getReplacementChar(node);

  if (!replacementChar) {
    return node;
  }

  return {
    ...node,
    // Special handling for Duration type to avoid obfuscating reserved characters like 's', 'm', 'h', etc.
    textValue:
      node.type === 'Duration'
        ? ''
        : obfuscateText(node.textValue, replacementChar),
    value: obfuscateText(String(node.value), replacementChar),
  };
}

function obfuscateStatement(
  node: FilterFieldStatementNode,
): FilterFieldStatementNode {
  return {
    ...node,
    key: obfuscateFilterFieldLeafNode(node.key),
    comparisonOperator: node.comparisonOperator,
    value: obfuscateFilterFieldLeafNode(node.value),
  };
}

function obfuscateGroupNode(
  groupNode: FilterFieldGroupNode,
): FilterFieldGroupNode {
  return {
    ...groupNode,
    children: groupNode.children.map((node) => {
      if (node.type === 'Group') {
        return obfuscateGroupNode(node);
      }
      if (node.type === 'Statement') {
        return obfuscateStatement(node);
      }
      return node as FilterFieldNode;
    }),
  };
}

/**
 * Obfuscates a filter field value, so that no customer internals are included
 * @example
 * ```
 * input: obfuscateFilterString("foo = bar AND baz = 1")
 * output: kkk = sssss AND kkk = n
 *```
 * @param filterString - filter field value
 * @internal
 */
export function obfuscateFilterString(
  filterString: string,
  validatorMap?: FilterFieldValidatorMap,
  parserConfig?: {
    searchConversion?: boolean;
    jsonPathConversion?: boolean;
    ipAddressConversion?: boolean;
    uidConversion?: boolean;
    timestampConversion?: boolean;
    smartscapeIdConversion?: boolean;
  },
) {
  const tree = convertStringToFilterFieldTree(filterString, {
    validatorMap,
    parserConfig,
  });
  if (tree.tree) {
    return convertFilterFieldTreeToString(obfuscateGroupNode(tree.tree));
  }
  return 'no filter tree';
}
